CoordenadaGrid obter_coordenada_borda(char* str) {
    CoordenadaGrid coord = {15, 9}; // Padrão caso não encontre (vai retornar espaço)

    if (strcmp(str, "canto_sup_dir") == 0) coord.coluna = 11;
    else if (strcmp(str, "canto_sup_esq") == 0) coord.coluna = 9;
    else if (strcmp(str, "canto_inf_dir") == 0) coord.coluna = 14;
    else if (strcmp(str, "canto_inf_esq") == 0) coord.coluna = 13;
    else if (strcmp(str, "borda_horizontal") == 0) coord.coluna = 10;
    else if (strcmp(str, "borda_vertical") == 0) coord.coluna = 12;

    return coord;
}

// Função que converte um caractere ASCII para a sua posição (Coluna, Linha) na imagem
CoordenadaGrid obter_coordenada_caractere(char c) {
    CoordenadaGrid coord = {0, 4}; // Padrão caso não encontre (vai retornar espaço)

    // Letras Maiúsculas (A-P estão na Linha 0, Q-Z na Linha 1)
    if (c >= 'A' && c <= 'P') {
        coord.coluna = c - 'A';
        coord.linha = 0;
    }
    else if (c >= 'Q' && c <= 'Z') {
        coord.coluna = c - 'Q';
        coord.linha = 1;
    }
    // Letras Minúsculas (a-p estão na Linha 2, q-z na Linha 3)
    else if (c >= 'a' && c <= 'p') {
        coord.coluna = c - 'a';
        coord.linha = 2;
    }
    else if (c >= 'q' && c <= 'z') {
        coord.coluna = c - 'q';
        coord.linha = 3;
    }
    // Números (0-9 estão na Linha 8, começando na Coluna 6)
    else if (c >= '0' && c <= '9') {
        coord.coluna = 6 + (c - '0');
        coord.linha = 7;
    }
    // Símbolos especiais
    else if (c == ' ') {
        coord.coluna = 0;
        coord.linha = 4;
    }
    else if (c == '(') {
        coord.coluna = 10;
        coord.linha = 1;
    }
    else if (c == ')') {
        coord.coluna = 11;
        coord.linha = 1;
    }
    else if (c == ':') {
        coord.coluna = 12;
        coord.linha = 1;
    }
    else if (c == ';') {
        coord.coluna = 13;
        coord.linha = 1;
    }
    else if (c == '[') {
        coord.coluna = 14;
        coord.linha = 1;
    }
    else if (c == ']') {
        coord.coluna = 15;
        coord.linha = 1;
    }
    else if (c == '-') { 
        coord.coluna = 3;
        coord.linha = 6;
    }
    else if (c == '?') { 
        coord.coluna = 6;
        coord.linha = 6;
    }
    else if (c == '!') { 
        coord.coluna = 7;
        coord.linha = 6;
    }
    else if (c == '.') { 
        coord.coluna = 8;
        coord.linha = 6;
    }
    else if (c == '<') { 
        coord.coluna = 12;
        coord.linha = 6;
    }
    else if (c == '>') { 
        coord.coluna = 13;
        coord.linha = 6;
    }
    else if (c == '/') { 
        coord.coluna = 3;
        coord.linha = 7;
    }
    else if (c == ',') { 
        coord.coluna = 4;
        coord.linha = 7;
    }

    return coord;
}

// Desenha um único caractere de 8x8 na tela VGA (com fundo transparente)
void desenhar_caractere(int grid_coluna, int grid_linha, CoordenadaGrid coord) {
    // 1. Garante que a escrita está dentro dos limites do grid de 20x18
    if (grid_coluna < 0 || grid_coluna >= MAX_COLUNAS || grid_linha < 0 || grid_linha >= MAX_LINHAS) {
        return; 
    }

    int pixel_x_inicial = OFFSET_X + (grid_coluna * 8);
    int pixel_y_inicial = OFFSET_Y + (grid_linha * 8);


    int img_start_x = (coord.coluna * 9); 
    int img_start_y = (coord.linha * 9); 

    for (int y = 0; y < 8; y++) {
        for (int x = 0; x < 8; x++) {
            unsigned short cor_pixel = imagem_data[img_start_y + y][img_start_x + x];
            
            // 0xFBE5 é o rosa de fundo transparente da imagem original
            if (cor_pixel != 0xFBE5) {
                // Desenha na tela mapeada diretamente para o grid centralizado
                write_pixel(pixel_x_inicial + x, pixel_y_inicial + y, cor_pixel);
            }
        }
    }
}

// Função para desenhar um texto completo (String)
void escrever_texto(int caixa_x, int caixa_y, const char *texto) {
    for (int i = 0; texto[i] != '\0'; i++) {
        desenhar_caractere(caixa_x + i, caixa_y, obter_coordenada_caractere(texto[i]));
    }
}

void imprimir_caixa_dialogo() {
    desenhar_caractere(0, 12, obter_coordenada_borda("canto_sup_esq"));
    desenhar_caractere(19, 12, obter_coordenada_borda("canto_sup_dir"));
    desenhar_caractere(0, 17, obter_coordenada_borda("canto_inf_esq"));
    desenhar_caractere(19, 17, obter_coordenada_borda("canto_inf_dir"));
    for (int i = 13; i < 17; i++) {
        desenhar_caractere(0, i, obter_coordenada_borda("borda_vertical"));
        desenhar_caractere(19, i, obter_coordenada_borda("borda_vertical"));
    }
    for (int i = 1; i < 19; i++) {
        desenhar_caractere(i, 12, obter_coordenada_borda("borda_horizontal"));
        desenhar_caractere(i, 17, obter_coordenada_borda("borda_horizontal"));
    }
}


void escrever_texto_progressivo(int caixa_x,int caixa_y,const char *texto,int tempo){
    char buffer[400];

    int tamanho = strlen(texto);

    for(int i = 0; i < tamanho; i++)
    {
        strncpy(buffer,texto,i+1);
        buffer[i+1]='\0';

        escrever_texto(caixa_x,caixa_y,buffer);

        inverter_buffers();

        delay(tempo);
    }
}